from pathlib import Path
import json

def _cm_success(action, message, data=None):
    if message is None or message == '':
        message = str(action) + ' completed'
    return {'ok': True, 'action': str(action), 'message': str(message), 'data': data, 'error': None}

def _cm_failure(action, message, error, data=None):
    if message is None or message == '':
        message = str(action) + ' failed'
    if error is None or error == '':
        error = message
    return {'ok': False, 'action': str(action), 'message': str(message), 'data': data, 'error': str(error)}
SKILL_ROOT = Path(__file__).resolve().parent
DATA_DIR = SKILL_ROOT / 'data'
DATA_DIR.mkdir(parents=True, exist_ok=True)
DATA_DIR.mkdir(parents=True, exist_ok=True)
NOTES_FILE = DATA_DIR / 'notes.json'

def add_note(content):
    if not content:
        return _cm_failure('add_note', 'Note content cannot be empty.', 'EMPTY_CONTENT')
    notes = []
    if NOTES_FILE.exists():
        with open(NOTES_FILE, 'r') as file:
            notes = json.load(file)
    notes.append(content)
    with open(NOTES_FILE, 'w') as file:
        json.dump(notes, file)
    return _cm_success('add_note', 'Note added successfully.', {'note': content})

def list_notes():
    notes = []
    if NOTES_FILE.exists():
        with open(NOTES_FILE, 'r') as file:
            notes = json.load(file)
    return _cm_success('list_notes', 'Notes fetched successfully.', {'notes': notes})

def schema():
    return {'package': 'src/api.py', 'endpoints': {'add_note': {'args': ['content'], 'returns': 'dict'}, 'list_notes': {'args': [], 'returns': 'dict'}}, 'response_format': "{'status': 'success|failure', 'action': str, 'message': str, 'data': dict}", 'storage_notes': NOTES_FILE.as_posix(), 'notes': 'A simple in-memory note taking API.'}

